def is_perfect_number(num):
    if num <= 1:
        return False

    sum_divisors = 1  # 1 is always a divisor for numbers greater than 1
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            sum_divisors += i
            if i * i != num:  # Add the other divisor if it's not the same as i
                sum_divisors += num // i

    return sum_divisors == num

if __name__ == "__main__":
    # Örnek kullanım
    print(is_perfect_number(6))    # True (1 + 2 + 3 = 6)
    print(is_perfect_number(28))   # True (1 + 2 + 4 + 7 + 14 = 28)
    print(is_perfect_number(496))  # True
    print(is_perfect_number(8128)) # True
    print(is_perfect_number(12))   # False (1 + 2 + 3 + 4 + 6 = 16 != 12)
    print(is_perfect_number(1))    # False
    print(is_perfect_number(0))    # False
    print(is_perfect_number(-5))   # False

    # Kullanıcıdan giriş alma örneği
    try:
        user_input = int(input("Bir sayı girin: "))
        if is_perfect_number(user_input):
            print(f"{user_input} mükemmel bir sayıdır.")
        else:
            print(f"{user_input} mükemmel bir sayı değildir.")
    except ValueError:
        print("Geçersiz giriş. Lütfen bir tam sayı girin.")
